  try {
    const id = c.req.param('id');
    await db.delete(users).where(eq(users.id, id));
    return c.json({ success: true, message: '用户已删除' });
  } catch (error) {
    console.error('Delete user error:', error);
    return c.json({ success: false, message: '服务器错误' }, 500);
  }
});

