import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { drizzle } from 'drizzle-orm/bun-sqlite';
import { Database } from 'bun:sqlite';
import { v4 as uuid } from 'uuid';
import * as schema from '../db/schema';
import { users, roles, patients, studies, series, images, reports, reportTemplates, sessions, auditLogs } from '../db/schema';
import { eq } from 'drizzle-orm';

// Import route handlers
import auth from '../routes/auth';
import patientsRouter from '../routes/patients';
import studiesRouter from '../routes/studies';
import imagesRouter from '../routes/images';
import reportsRouter from '../routes/reports';
import reportTemplatesRouter from '../routes/report-templates';
import usersRouter from '../routes/users';
import rolesRouter from '../routes/roles';
import auditLogsRouter from '../routes/audit-logs';

export interface TestContext {
  app: Hono;
  db: ReturnType<typeof drizzle>;
  sqlite: Database;
  adminToken: string;
  doctorToken: string;
  adminUserId: string;
  doctorUserId: string;
  adminRoleId: string;
  doctorRoleId: string;
}

export async function createTestApp(): Promise<TestContext> {
  // Create in-memory SQLite database
  const sqlite = new Database(':memory:');
  const db = drizzle(sqlite, { schema });

  // Create tables
  sqlite.exec(`
    CREATE TABLE IF NOT EXISTS roles (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL UNIQUE,
      description TEXT,
      permissions TEXT NOT NULL DEFAULT '{}',
      is_system INTEGER DEFAULT 0 NOT NULL,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS users (
      id TEXT PRIMARY KEY,
      username TEXT NOT NULL UNIQUE,
      email TEXT NOT NULL UNIQUE,
      password_hash TEXT NOT NULL,
      display_name TEXT NOT NULL,
      avatar TEXT,
      role_id TEXT REFERENCES roles(id),
      status TEXT CHECK(status IN ('active', 'disabled', 'locked')) DEFAULT 'active' NOT NULL,
      last_login_at TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL,
      updated_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS sessions (
      id TEXT PRIMARY KEY,
      user_id TEXT REFERENCES users(id) NOT NULL,
      token TEXT NOT NULL UNIQUE,
      refresh_token TEXT NOT NULL UNIQUE,
      device_info TEXT,
      ip_address TEXT,
      expires_at TEXT NOT NULL,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS patients (
      id TEXT PRIMARY KEY,
      mrn TEXT NOT NULL UNIQUE,
      name TEXT NOT NULL,
      gender TEXT CHECK(gender IN ('male', 'female', 'other')) NOT NULL,
      birth_date TEXT NOT NULL,
      phone TEXT,
      email TEXT,
      id_card TEXT,
      insurance_no TEXT,
      address TEXT,
      avatar TEXT,
      notes TEXT,
      tags TEXT DEFAULT '[]',
      custom_fields TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL,
      updated_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS studies (
      id TEXT PRIMARY KEY,
      patient_id TEXT REFERENCES patients(id) NOT NULL,
      study_date TEXT NOT NULL,
      study_time TEXT,
      study_type TEXT CHECK(study_type IN ('oct', 'fundus', 'ffa', 'icga', 'vf', 'octa', 'other')) NOT NULL,
      modality TEXT NOT NULL,
      device TEXT,
      physician_id TEXT REFERENCES users(id),
      status TEXT CHECK(status IN ('pending', 'in_progress', 'diagnosed', 'reported')) DEFAULT 'pending' NOT NULL,
      description TEXT,
      tags TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL,
      updated_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS series (
      id TEXT PRIMARY KEY,
      study_id TEXT REFERENCES studies(id) NOT NULL,
      series_number INTEGER NOT NULL,
      series_description TEXT,
      modality TEXT NOT NULL,
      body_part TEXT,
      image_count INTEGER DEFAULT 0 NOT NULL,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS images (
      id TEXT PRIMARY KEY,
      series_id TEXT REFERENCES series(id) NOT NULL,
      instance_number INTEGER NOT NULL,
      file_path TEXT NOT NULL,
      file_size INTEGER NOT NULL,
      file_hash TEXT NOT NULL,
      format TEXT CHECK(format IN ('dicom', 'jpeg', 'png', 'tiff', 'bmp')) NOT NULL,
      width INTEGER NOT NULL,
      height INTEGER NOT NULL,
      bits_allocated INTEGER DEFAULT 8 NOT NULL,
      thumbnail_path TEXT,
      metadata TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS report_templates (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL,
      type TEXT CHECK(type IN ('oct', 'fundus', 'ffa', 'icga', 'vf', 'octa', 'comprehensive', 'custom')) NOT NULL,
      description TEXT,
      fields TEXT NOT NULL,
      layout TEXT NOT NULL,
      is_system INTEGER DEFAULT 0 NOT NULL,
      created_by TEXT REFERENCES users(id),
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL,
      updated_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS reports (
      id TEXT PRIMARY KEY,
      study_id TEXT REFERENCES studies(id) NOT NULL,
      patient_id TEXT REFERENCES patients(id) NOT NULL,
      template_id TEXT REFERENCES report_templates(id) NOT NULL,
      title TEXT NOT NULL,
      content TEXT NOT NULL,
      images TEXT DEFAULT '[]',
      status TEXT CHECK(status IN ('draft', 'pending_review', 'reviewed', 'published')) DEFAULT 'draft' NOT NULL,
      reviewer_id TEXT REFERENCES users(id),
      review_notes TEXT,
      published_at TEXT,
      created_by TEXT REFERENCES users(id) NOT NULL,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL,
      updated_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS audit_logs (
      id TEXT PRIMARY KEY,
      user_id TEXT REFERENCES users(id) NOT NULL,
      action TEXT NOT NULL,
      resource TEXT NOT NULL,
      resource_id TEXT,
      details TEXT,
      ip_address TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS annotations (
      id TEXT PRIMARY KEY,
      image_id TEXT REFERENCES images(id) NOT NULL,
      user_id TEXT REFERENCES users(id) NOT NULL,
      layer_id TEXT REFERENCES layers(id),
      type TEXT CHECK(type IN ('measurement', 'arrow', 'text', 'freehand', 'roi', 'highlight')) NOT NULL,
      geometry TEXT NOT NULL,
      style TEXT NOT NULL,
      label TEXT,
      notes TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL,
      updated_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS layers (
      id TEXT PRIMARY KEY,
      image_id TEXT REFERENCES images(id) NOT NULL,
      name TEXT NOT NULL,
      type TEXT CHECK(type IN ('image', 'annotation', 'ai_result')) NOT NULL,
      visible INTEGER DEFAULT 1 NOT NULL,
      opacity REAL DEFAULT 1 NOT NULL,
      locked INTEGER DEFAULT 0 NOT NULL,
      sort_order INTEGER DEFAULT 0 NOT NULL,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );

    CREATE TABLE IF NOT EXISTS patient_tags (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL UNIQUE,
      color TEXT NOT NULL,
      description TEXT,
      created_at TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL
    );
  `);

  // Create test app with routes
  const app = new Hono();

  // Override db module for routes - we'll need to monkey-patch this
  // For now, we'll create a wrapper approach
  app.use('*', cors());

  // Health check
  app.get('/health', (c) => c.json({ status: 'ok' }));

  // We need to intercept the db import in routes
  // The routes import db from '../db' - we'll need to mock this
  // For integration tests, let's create route handlers that use our test db

  // Create wrapper routes that use test db
  const testAuth = createTestAuthRoutes(db);
  const testPatients = createTestPatientRoutes(db);
  const testStudies = createTestStudyRoutes(db);
  const testImages = createTestImageRoutes(db);
  const testReports = createTestReportRoutes(db);
  const testReportTemplates = createTestReportTemplateRoutes(db);
  const testUsers = createTestUserRoutes(db);
  const testRoles = createTestRoleRoutes(db);
  const testAuditLogs = createTestAuditLogRoutes(db);

  app.route('/api/auth', testAuth);
  app.route('/api/patients', testPatients);
  app.route('/api/studies', testStudies);
  app.route('/api/images', testImages);
  app.route('/api/reports', testReports);
  app.route('/api/report-templates', testReportTemplates);
  app.route('/api/users', testUsers);
  app.route('/api/roles', testRoles);
  app.route('/api/audit-logs', testAuditLogs);

  // Seed test data
  const adminRoleId = uuid();
  const doctorRoleId = uuid();

  await db.insert(roles).values([
    {
      id: adminRoleId,
      name: '管理员',
      description: '系统管理员',
      permissions: JSON.stringify({ all: true }),
      isSystem: true,
      createdAt: new Date().toISOString(),
    },
    {
      id: doctorRoleId,
      name: '医生',
      description: '眼科医生',
      permissions: JSON.stringify({ patients: { read: true } }),
      isSystem: true,
      createdAt: new Date().toISOString(),
    },
  ]);

  const adminPassword = await Bun.password.hash('admin123');
  const adminUserId = uuid();
  await db.insert(users).values({
    id: adminUserId,
    username: 'admin',
    email: 'admin@test.com',
    passwordHash: adminPassword,
    displayName: 'Test Admin',
    roleId: adminRoleId,
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  });

  const doctorPassword = await Bun.password.hash('doctor123');
  const doctorUserId = uuid();
  await db.insert(users).values({
    id: doctorUserId,
    username: 'doctor',
    email: 'doctor@test.com',
    passwordHash: doctorPassword,
    displayName: 'Test Doctor',
    roleId: doctorRoleId,
    status: 'active',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  });

  // Login to get tokens
  const adminLoginRes = await app.request('/api/auth/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username: 'admin', password: 'admin123' }),
  });
  const adminLoginData = await adminLoginRes.json();
  const adminToken = adminLoginData.data?.token || '';

  const doctorLoginRes = await app.request('/api/auth/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username: 'doctor', password: 'doctor123' }),
  });
  const doctorLoginData = await doctorLoginRes.json();
  const doctorToken = doctorLoginData.data?.token || '';

  return {
    app,
    db,
    sqlite,
    adminToken,
    doctorToken,
    adminUserId,
    doctorUserId,
    adminRoleId,
    doctorRoleId,
  };
}

export function authHeaders(token: string): Record<string, string> {
  return {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
  };
}

export async function cleanupTestApp(ctx: TestContext): Promise<void> {
  ctx.sqlite.close();
}

// Helper to create route handlers that use test db
// We need to recreate the route logic since the routes import db directly

function createTestAuthRoutes(db: any): Hono {
  const router = new Hono();

  router.post('/login', async (c) => {
    try {
      const { username, password } = await c.req.json();

      const user = await db.query.users.findFirst({
        where: eq(users.username, username),
        with: { role: true },
      });

      if (!user) {
        return c.json({ success: false, message: '用户名或密码错误' }, 401);
      }

      const isValid = await Bun.password.verify(password, user.passwordHash);
      if (!isValid) {
        return c.json({ success: false, message: '用户名或密码错误' }, 401);
      }

      if (user.status !== 'active') {
        return c.json({ success: false, message: '账号已被禁用' }, 403);
      }

      const token = uuid();
      const refreshToken = uuid();

      await db.insert(sessions).values({
        id: uuid(),
        userId: user.id,
        token,
        refreshToken,
        deviceInfo: { userAgent: c.req.header('User-Agent') },
        ipAddress: c.req.header('X-Forwarded-For'),
        expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
      });

      await db.update(users)
        .set({ lastLoginAt: new Date().toISOString() })
        .where(eq(users.id, user.id));

      return c.json({
        success: true,
        data: {
          user: {
            id: user.id,
            username: user.username,
            email: user.email,
            displayName: user.displayName,
            avatar: user.avatar,
            role: user.role,
          },
          token,
          refreshToken,
        },
      });
    } catch (error) {
      console.error('Login error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.post('/refresh', async (c) => {
    try {
      const { refreshToken } = await c.req.json();

      const session = await db.query.sessions.findFirst({
        where: eq(sessions.refreshToken, refreshToken),
      });

      if (!session) {
        return c.json({ success: false, message: '无效的刷新令牌' }, 401);
      }

      if (new Date(session.expiresAt) < new Date()) {
        return c.json({ success: false, message: '会话已过期' }, 401);
      }

      const newToken = uuid();
      const newRefreshToken = uuid();

      await db.update(sessions)
        .set({
          token: newToken,
          refreshToken: newRefreshToken,
          expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
        })
        .where(eq(sessions.id, session.id));

      return c.json({
        success: true,
        data: { token: newToken, refreshToken: newRefreshToken },
      });
    } catch (error) {
      console.error('Refresh error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.post('/logout', async (c) => {
    try {
      const token = c.req.header('Authorization')?.replace('Bearer ', '');
      if (token) {
        await db.delete(sessions).where(eq(sessions.token, token));
      }
      return c.json({ success: true, message: '已退出登录' });
    } catch (error) {
      console.error('Logout error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.get('/me', async (c) => {
    try {
      const token = c.req.header('Authorization')?.replace('Bearer ', '');
      if (!token) {
        return c.json({ success: false, message: '未授权' }, 401);
      }

      const session = await db.query.sessions.findFirst({
        where: eq(sessions.token, token),
        with: { user: { with: { role: true } } },
      });

      if (!session || new Date(session.expiresAt) < new Date()) {
        return c.json({ success: false, message: '会话已过期' }, 401);
      }

      return c.json({
        success: true,
        data: {
          id: session.user.id,
          username: session.user.username,
          email: session.user.email,
          displayName: session.user.displayName,
          avatar: session.user.avatar,
          role: session.user.role,
        },
      });
    } catch (error) {
      console.error('Get profile error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  return router;
}

function createTestPatientRoutes(db: any): Hono {
  const router = new Hono();

  router.get('/', async (c) => {
    try {
      const page = Number(c.req.query('page')) || 1;
      const pageSize = Number(c.req.query('pageSize')) || 20;
      const offset = (page - 1) * pageSize;

      const allPatients = await db.query.patients.findMany({
        limit: pageSize,
        offset,
        orderBy: (p: any, { desc }: any) => [desc(p.createdAt)],
      });

      const countResult = await db.select().from(patients);
      const total = countResult.length;

      return c.json({
        success: true,
        data: { items: allPatients, total, page, pageSize, totalPages: Math.ceil(total / pageSize) },
      });
    } catch (error) {
      console.error('Get patients error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.get('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const patient = await db.query.patients.findFirst({
        where: eq(patients.id, id),
      });

      if (!patient) {
        return c.json({ success: false, message: '患者未找到' }, 404);
      }

      return c.json({ success: true, data: patient });
    } catch (error) {
      console.error('Get patient error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const id = uuid();

      await db.insert(patients).values({
        id,
        ...body,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      });

      const patient = await db.query.patients.findFirst({ where: eq(patients.id, id) });
      return c.json({ success: true, data: patient }, 201);
    } catch (error) {
      console.error('Create patient error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.put('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const body = await c.req.json();

      await db.update(patients)
        .set({ ...body, updatedAt: new Date().toISOString() })
        .where(eq(patients.id, id));

      const patient = await db.query.patients.findFirst({ where: eq(patients.id, id) });
      return c.json({ success: true, data: patient });
    } catch (error) {
      console.error('Update patient error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.delete('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      await db.delete(patients).where(eq(patients.id, id));
      return c.json({ success: true, message: '患者已删除' });
    } catch (error) {
      console.error('Delete patient error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  return router;
}

function createTestStudyRoutes(db: any): Hono {
  const router = new Hono();

  router.get('/', async (c) => {
    try {
      const page = Number(c.req.query('page')) || 1;
      const pageSize = Number(c.req.query('pageSize')) || 20;
      const patientId = c.req.query('patientId');
      const offset = (page - 1) * pageSize;

      let allStudies;
      if (patientId) {
        allStudies = await db.query.studies.findMany({
          where: eq(studies.patientId, patientId),
          limit: pageSize,
          offset,
          orderBy: (s: any, { desc }: any) => [desc(s.studyDate)],
        });
      } else {
        allStudies = await db.query.studies.findMany({
          limit: pageSize,
          offset,
          orderBy: (s: any, { desc }: any) => [desc(s.studyDate)],
        });
      }

      const countResult = await db.select().from(studies);
      const total = countResult.length;

      return c.json({
        success: true,
        data: { items: allStudies, total, page, pageSize, totalPages: Math.ceil(total / pageSize) },
      });
    } catch (error) {
      console.error('Get studies error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.get('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const study = await db.query.studies.findFirst({ where: eq(studies.id, id) });

      if (!study) {
        return c.json({ success: false, message: '检查未找到' }, 404);
      }

      return c.json({ success: true, data: study });
    } catch (error) {
      console.error('Get study error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const id = uuid();

      await db.insert(studies).values({
        id,
        ...body,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      });

      const study = await db.query.studies.findFirst({ where: eq(studies.id, id) });
      return c.json({ success: true, data: study }, 201);
    } catch (error) {
      console.error('Create study error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.put('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const body = await c.req.json();

      await db.update(studies)
        .set({ ...body, updatedAt: new Date().toISOString() })
        .where(eq(studies.id, id));

      const study = await db.query.studies.findFirst({ where: eq(studies.id, id) });
      return c.json({ success: true, data: study });
    } catch (error) {
      console.error('Update study error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.delete('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      await db.delete(studies).where(eq(studies.id, id));
      return c.json({ success: true, message: '检查已删除' });
    } catch (error) {
      console.error('Delete study error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.put('/:id/status', async (c) => {
    try {
      const id = c.req.param('id');
      const { status } = await c.req.json();

      await db.update(studies)
        .set({ status, updatedAt: new Date().toISOString() })
        .where(eq(studies.id, id));

      return c.json({ success: true, message: '状态已更新' });
    } catch (error) {
      console.error('Update study status error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  return router;
}

function createTestImageRoutes(db: any): Hono {
  const router = new Hono();

  router.get('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      const image = await db.query.images.findFirst({ where: eq(images.id, id) });

      if (!image) {
        return c.json({ success: false, message: '图像未找到' }, 404);
      }

      return c.json({ success: true, data: image });
    } catch (error) {
      console.error('Get image error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  router.post('/upload', async (c) => {
    try {
      const formData = await c.req.formData();
      const file = formData.get('file') as File;
      const seriesId = formData.get('seriesId') as string;
      const instanceNumber = Number(formData.get('instanceNumber')) || 1;

      if (!file) {
        return c.json({ success: false, message: '请选择文件' }, 400);
      }

      const ext = file.name.split('.').pop();
      const id = uuid();
      const filename = `${id}.${ext}`;

      await db.insert(images).values({
        id,
        seriesId,
        instanceNumber,
        filePath: filename,
        fileSize: file.size,
        fileHash: 'test-hash',
        format: ext as any,
        width: 100,
        height: 100,
        createdAt: new Date().toISOString(),
      });

      const image = await db.query.images.findFirst({ where: eq(images.id, id) });
      return c.json({ success: true, data: image }, 201);
    } catch (error) {
      console.error('Upload image error:', error);
      return c.json({ success: false, message: '上传失败' }, 500);
    }
  });

  router.delete('/:id', async (c) => {
    try {
      const id = c.req.param('id');
      await db.delete(images).where(eq(images.id, id));
      return c.json({ success: true, message: '图像已删除' });
    } catch (error) {
      console.error('Delete image error:', error);
      return c.json({ success: false, message: '服务器错误' }, 500);
    }
  });

  return router;
}

