describe('Images API', () => {
  let ctx: TestContext;
  let testPatientId: string;
  let testStudyId: string;
  let testSeriesId: string;
  let testImageId: string;

  beforeAll(async () => {
    ctx = await createTestApp();

    // Create test patient
    const patientRes = await ctx.app.request('/api/patients', {
      method: 'POST',
      headers: authHeaders(ctx.adminToken),
      body: JSON.stringify({
        mrn: 'IMG_PATIENT_001',
        name: '图像测试患者',
        gender: 'female',
        birthDate: '1975-06-15',
      }),
    });
    const patientData = await patientRes.json();
    testPatientId = patientData.data.id;

    // Create test study
    const studyRes = await ctx.app.request('/api/studies', {
      method: 'POST',
      headers: authHeaders(ctx.adminToken),
      body: JSON.stringify({
        patientId: testPatientId,
        studyDate: '2024-01-15',
        studyType: 'oct',
        modality: 'OCT',
      }),
    });
    const studyData = await studyRes.json();
    testStudyId = studyData.data.id;

    // Create test series directly in DB
    testSeriesId = uuid();
    await ctx.db.insert(ctx.db.query.series ? undefined : undefined).execute?.() || 
      await (ctx as any).sqlite.run(
        `INSERT INTO series (id, study_id, series_number, modality, image_count) VALUES (?, ?, ?, ?, ?)`,
        [testSeriesId, testStudyId, 1, 'OCT', 0]
      );
  });

  afterAll(async () => {
    await cleanupTestApp(ctx);
  });

  describe('POST /api/images/upload', () => {
    it('should upload an image', async () => {
      // Create a test file
      const file = new File(['test image content'], 'test.png', { type: 'image/png' });
      const formData = new FormData();
      formData.append('file', file);
      formData.append('seriesId', testSeriesId);
      formData.append('instanceNumber', '1');

      const res = await ctx.app.request('/api/images/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${ctx.adminToken}`,
        },
        body: formData,
      });

      expect(res.status).toBe(201);
      const data = await res.json();
      expect(data.success).toBe(true);
      expect(data.data.seriesId).toBe(testSeriesId);
      expect(data.data.format).toBe('png');
      testImageId = data.data.id;
    });

    it('should reject upload without file', async () => {
      const formData = new FormData();
      formData.append('seriesId', testSeriesId);

      const res = await ctx.app.request('/api/images/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${ctx.adminToken}`,
        },
        body: formData,
      });

      expect(res.status).toBe(400);
      const data = await res.json();
      expect(data.success).toBe(false);
    });
  });

  describe('GET /api/images/:id', () => {
    it('should get image by ID', async () => {
      const res = await ctx.app.request(`/api/images/${testImageId}`, {
        headers: authHeaders(ctx.adminToken),
      });

      expect(res.status).toBe(200);
      const data = await res.json();
      expect(data.success).toBe(true);
      expect(data.data.id).toBe(testImageId);
      expect(data.data.format).toBe('png');
    });

    it('should return 404 for non-existent image', async () => {
      const res = await ctx.app.request('/api/images/non-existent-id', {
        headers: authHeaders(ctx.adminToken),
      });

      expect(res.status).toBe(404);
      const data = await res.json();
      expect(data.success).toBe(false);
    });
  });

  describe('DELETE /api/images/:id', () => {
    it('should delete image', async () => {
      // Upload another image to delete
      const file = new File(['delete me'], 'delete.png', { type: 'image/png' });
      const formData = new FormData();
      formData.append('file', file);
      formData.append('seriesId', testSeriesId);
      formData.append('instanceNumber', '2');

      const uploadRes = await ctx.app.request('/api/images/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${ctx.adminToken}`,
        },
        body: formData,
      });
      const uploadData = await uploadRes.json();
      const deleteId = uploadData.data.id;

      // Delete
      const res = await ctx.app.request(`/api/images/${deleteId}`, {
        method: 'DELETE',
        headers: authHeaders(ctx.adminToken),
      });

      expect(res.status).toBe(200);
      const data = await res.json();
      expect(data.success).toBe(true);

      // Verify deleted
      const getRes = await ctx.app.request(`/api/images/${deleteId}`, {
        headers: authHeaders(ctx.adminToken),
      });
      expect(getRes.status).toBe(404);
    });
  });
});

