        method: 'POST',
        headers: authHeaders(ctx.adminToken),
        body: JSON.stringify({
          username: 'todelete',
          email: 'todelete@test.com',
          password: 'password123',
          displayName: '待删除用户',
          roleId: ctx.adminRoleId,
        }),
      });
      const createData = await createRes.json();
      const deleteId = createData.data.id;

      // Delete
