router.get('/', async (c) => {
  try {
    const page = Number(c.req.query('page')) || 1;
    const pageSize = Number(c.req.query('pageSize')) || 20;
    const offset = (page - 1) * pageSize;

    const allUsers = await db.query.users.findMany({
      limit: pageSize,
      offset,
      orderBy: (u: any, { desc }: any) => [desc(u.createdAt)],
    });

    // Enrich with roles
    const allRoles = await db.query.roles.findMany();
    const roleMap = new Map(allRoles.map((r: any) => [r.id, r]));
    const enrichedUsers = allUsers.map((u: any) => ({ ...u, role: roleMap.get(u.roleId) }));

    const countResult = await db.select().from(users);
    const total = countResult.length;

    return c.json({
      success: true,
      data: { items: enrichedUsers, total, page, pageSize, totalPages: Math.ceil(total / pageSize) },
    });
  } catch (error) {
    console.error('Get users error:', error);
    return c.json({ success: false, message: '服务器错误' }, 500);
  }
});

